<?php require 'db_connect.php'; if($_SERVER['REQUEST_METHOD']=='POST'){ if(!isset($_SESSION['user'])){ header('Location: login.php'); exit; } $user_id = $_SESSION['user']['id']; $fullname = trim($_POST['fullname']); $address = trim($_POST['address']); $method = $_POST['method']; $cart = isset($_SESSION['cart']) ? $_SESSION['cart'] : []; if(count($cart)==0){ header('Location: cart.php'); exit; } $total = 0; foreach($cart as $it) $total += $it['price']*$it['qty']; $pdo->beginTransaction(); try{ $stmt = $pdo->prepare("INSERT INTO orders (user_id,total_amount,shipping_address,payment_method) VALUES (?,?,?,?)"); $stmt->execute([$user_id,$total,$address,$method]); $order_id = $pdo->lastInsertId(); $stmt_item = $pdo->prepare("INSERT INTO order_items (order_id,product_name,unit_price,quantity) VALUES (?,?,?,?)"); foreach($cart as $it){ $stmt_item->execute([$order_id,$it['name'],$it['price'],$it['qty']]); } $pdo->commit(); unset($_SESSION['cart']); echo "<h2>Order placed (simulation). Order ID: $order_id</h2><p><a href='index.php'>Continue shopping</a></p>"; } catch (Exception $e){ $pdo->rollBack(); echo "Order failed: ".$e->getMessage(); } } ?>